import json
import os, datetime  # Used to determine the time
from flask import Flask, jsonify  
from google.cloud import pubsub_v1  # For Cloud Pub/Sub functionality


# Setup Flask app with a route for cloud function to listen on
app = Flask(__name__) 

@app.route('/')  # A decorator
def cloudfunction():  # This is the entry point

    # Get the name of the message attribute
    msg_topic = os.environ['pubsub-topic'] 
    # Create a pubsub_v1 PublisherClient object to publish our messages
    publisher = pubsub_v1.PublisherClient()
    try:
        # Initialize our message_count and date_time_start to 0. 
        message_count, date_time_start = 0, datetime.datetime.now()

        print('Listening for messages on topic {}'.format(msg_topic))

        # Use subscription to poll Cloud Pub/Sub for any new messages
        pull_request = publisher.subscribe(msg_topic)

        # Create a dictionary variable to contain the count and datetime information we want
        stats = {'time_start': date_time_start}  
        # Set our first timestamp equal to 15 minutes ago, not current time 
        now = datetime.datetime.now() - datetime.timedelta(minutes=15) 

        # Use a while loop to run the message retrieval and count logic until we get a 404 message
        while True:
            # Retrieve 30 new messages and add them together into a variable 
            messages = pull_request.poll(minimum_message_count=30)

            if not messages:
                print('No more messages found.')
                break

            for message in messages:
                message_count +=1

            stats['time'] = datetime.datetime.now() # Add our current timestamp to the stats
            stats['count'] = message_count  # Update total message count in stats

            print(jsonify({'messages':stats}))

            # Return the stats dictionary to the Cloud Function
            return jsonify({'status':'Success', 'data':stats})

    finally:
        # Close the subscriber when done polling messages. This is good practice. 
        pull_request.stop()